import readline from 'node:readline/promises';

const CANCEL = Symbol('cancel');

function createRl() {
  return readline.createInterface({ input: process.stdin, output: process.stdout });
}

export function intro(message) { process.stdout.write(`${message}\n`); }
export function outro(message) { process.stdout.write(`${message}\n`); }
export function cancel(message) { process.stdout.write(`${message}\n`); }
export function isCancel(value) { return value === CANCEL; }

export async function text(options) {
  const rl = createRl();
  const suffix = options.defaultValue ? ` (${options.defaultValue})` : '';
  const answer = await rl.question(`${options.message}${suffix}: `);
  rl.close();
  const value = answer.trim() || options.defaultValue || '';
  if (value.toLowerCase() === 'cancel') return CANCEL;
  const error = options.validate?.(value);
  if (error) {
    process.stdout.write(`${error}\n`);
    return text(options);
  }
  return value;
}

export async function select(options) {
  process.stdout.write(`${options.message}\n`);
  options.options.forEach((option, index) => {
    process.stdout.write(`  ${index + 1}. ${option.label}${option.hint ? ` - ${option.hint}` : ''}\n`);
  });
  const rl = createRl();
  const answer = await rl.question('Select option number: ');
  rl.close();
  if (answer.trim().toLowerCase() === 'cancel') return CANCEL;
  const index = Number(answer.trim() || '1') - 1;
  return options.options[index]?.value ?? options.options[0].value;
}

export async function confirm(options) {
  const rl = createRl();
  const answer = await rl.question(`${options.message} ${options.initialValue === false ? '[y/N]' : '[Y/n]'}: `);
  rl.close();
  const normalized = answer.trim().toLowerCase();
  if (normalized === 'cancel') return CANCEL;
  if (!normalized) return options.initialValue ?? true;
  return ['y', 'yes'].includes(normalized);
}
